INSERT INTO news_items (title, summary, category, source_name, source_url, trending_score, is_featured, tags, published_at) VALUES
('GPT-5 Officially Announced: 10x Better Reasoning and Real-Time Multimodal', 'OpenAI announces GPT-5 with revolutionary improvements in reasoning, real-time voice, image generation, and coding. The model achieves near-human performance on complex benchmarks.', 'Models', 'OpenAI', 'https://openai.com', 98, true, '{"GPT-5","OpenAI","LLM","Multimodal"}', now() - interval '2 hours'),
('Google Gemini Ultra 2.0 Beats All Benchmarks', 'Google DeepMind releases Gemini Ultra 2.0 with 1M context window, native video understanding, and real-time code execution across 50+ languages.', 'Models', 'Google AI', 'https://deepmind.google', 95, true, '{"Gemini","Google","Benchmark","LLM"}', now() - interval '4 hours'),
('Anthropic Claude 4 Introduces Constitutional AI 2.0', 'Claude 4 launches with enhanced safety features, 500K context window, and groundbreaking computer use capabilities for autonomous agents.', 'Models', 'Anthropic', 'https://anthropic.com', 92, false, '{"Claude","Anthropic","Safety","Agents"}', now() - interval '6 hours'),
('HuggingFace Releases Open-Source GPT-4 Rival: Falcon 180B', 'The AI community celebrates as HuggingFace launches Falcon 180B, matching GPT-4 performance with full open weights available for commercial use.', 'Open Source', 'HuggingFace', 'https://huggingface.co', 88, false, '{"Falcon","OpenSource","HuggingFace","LLM"}', now() - interval '8 hours'),
('AI Coding Tools Now Write 60% of Production Code at Top Startups', 'A new survey reveals that 67% of Silicon Valley startups now use AI-generated code for majority of their codebase, with Cursor and GitHub Copilot leading adoption.', 'Industry', 'GitHub', 'https://github.com', 85, true, '{"Coding","Automation","Cursor","Copilot"}', now() - interval '10 hours'),
('Reddit Bans AI-Generated Content in 50+ Major Subreddits', 'Community revolt against AI spam leads to mass bans, creating new demand for AI detection tools and verified human content platforms.', 'Community', 'Reddit', 'https://reddit.com', 80, false, '{"Reddit","Content","Policy","Detection"}', now() - interval '12 hours'),
('Product Hunt AI Category Hits Record 500 Launches This Week', 'AI products dominate Product Hunt as investors pour $2B into early-stage AI startups. Key trends: AI agents, voice interfaces, and no-code platforms.', 'Startups', 'Product Hunt', 'https://producthunt.com', 77, false, '{"ProductHunt","Startups","Investment","Agents"}', now() - interval '14 hours'),
('YouTube Now Auto-Generates AI Summaries for All Videos', 'YouTube rolls out AI-powered video summaries, chapters, and Q&A features globally, transforming how users consume long-form content.', 'Products', 'YouTube', 'https://youtube.com', 74, false, '{"YouTube","Summaries","Video","Content"}', now() - interval '16 hours'),
('GitHub Trending: 50 AI Repos with 10K+ Stars This Week', 'AI agent frameworks, RAG pipelines, and multimodal models dominate GitHub trending. AutoGen, CrewAI, and LangGraph lead with massive community growth.', 'Open Source', 'GitHub', 'https://github.com', 71, false, '{"GitHub","OpenSource","Agents","RAG"}', now() - interval '18 hours'),
('AI Image Generation Market Reaches $12B: Who Wins?', 'Midjourney, DALL-E 3, Stable Diffusion, and Flux battle for dominance in the AI image market. Analysis of strengths, pricing, and future roadmaps.', 'Market', 'TechCrunch', 'https://techcrunch.com', 68, false, '{"ImageGeneration","Midjourney","DALLE","Market"}', now() - interval '20 hours'),
('New AI Regulation Framework Proposed by EU: What It Means', 'EU introduces comprehensive AI Act enforcement timeline, requiring transparency reports and safety audits for all frontier models by 2025.', 'Policy', 'EU Commission', 'https://ec.europa.eu', 65, false, '{"Regulation","EU","AIAct","Policy"}', now() - interval '22 hours'),
('Mistral AI Raises $600M Series B at $6B Valuation', 'European AI powerhouse Mistral raises massive funding round to compete with OpenAI and Google, with plans for specialized models and enterprise APIs.', 'Startups', 'Mistral AI', 'https://mistral.ai', 82, false, '{"Mistral","Funding","Europe","Startup"}', now() - interval '1 day')
