('Jasper', 'Enterprise AI content platform for teams. Generate branded content at scale with brand voice, tone, and style controls.', 'Content', 'https://jasper.ai', 'Paid', 4.2, '{"Content marketing","Brand content","SEO","Ads"}', '{"Enterprise","Marketing","Brand","Scale"}', false, false, 3800),
('n8n', 'Open-source AI workflow automation. Build complex automations connecting 400+ apps with AI agents, no coding required.', 'Automation', 'https://n8n.io', 'Free/Cloud', 4.7, '{"Automation","Workflows","Integration","AI agents"}', '{"Automation","No-code","Integration","Open-source"}', true, false, 6200),
('Make', 'Visual no-code automation platform. Connect any app, automate any workflow, add AI with drag-and-drop simplicity.', 'Automation', 'https://make.com', 'Free/Pro', 4.5, '{"Automation","Integration","Workflows","Business"}', '{"Automation","No-code","Integration","Visual"}', false, false, 7100),
