('DALL-E 3', 'OpenAI''s image generation model integrated into ChatGPT. Create highly detailed images with precise text rendering capabilities.', 'Image Generation', 'https://openai.com/dall-e-3', 'ChatGPT Plus', 4.6, '{"Image creation","Illustrations","Marketing","Design"}', '{"Images","OpenAI","ChatGPT","Generation"}', false, false, 8100),
('Stable Diffusion', 'Open-source AI image generation model. Run locally or use APIs. Unlimited generation with full customization and LoRA models.', 'Image Generation', 'https://stability.ai', 'Free', 4.4, '{"Image creation","Art","Custom models","Local AI"}', '{"OpenSource","Images","Local","Custom"}', false, false, 9400)
INSERT INTO business_ideas (title, problem, solution, target_audience, monetization, difficulty, opportunity_score, how_to_build, category, tags, is_featured) VALUES
('AI Personal Finance Coach', 'People struggle with budgeting, investing, and financial decisions. Financial advisors are expensive ($200-500/hr) and inaccessible.', 'An AI app that analyzes spending patterns, provides personalized investment advice, sets budgets automatically, and answers financial questions 24/7 in conversational language.', 'Millennials and Gen Z earning $40K-$150K who want financial guidance but can''t afford advisors', 'Freemium: $19/mo premium. Affiliate commissions on recommended products. B2B: white-label for banks.', 'Medium', 88, 'Use Bolt.new to build MVP in 48hrs. Connect Plaid API for bank data. Use GPT-4 for advice. Deploy on Supabase. Launch on Product Hunt.', 'FinTech', '{"Finance","AI Advisor","FinTech","Personal"}', true),
('AI Social Media Ghost Writer', 'Business owners and executives know they should post on LinkedIn/Twitter but don''t have time or writing skills. Hiring social media managers costs $3-8K/month.', 'AI that learns your communication style from past content, automatically generates posts in your voice, schedules them, and responds to comments. Full autopilot social presence.', 'CEOs, founders, and B2B professionals who need consistent social presence for lead generation', 'SaaS: $79-299/month per user. Agency white-label at $500+/month. Pay-per-post model.', 'Easy', 92, 'Build with Next.js + OpenAI. Fine-tune on user''s past posts. LinkedIn/Twitter API for scheduling. Deploy on Vercel + Supabase.', 'SaaS', '{"Social Media","Content","LinkedIn","Ghost Writing"}', true),
('AI Real Estate Deal Finder', 'Real estate investors spend 40+ hours per week analyzing hundreds of properties to find undervalued deals. Most miss opportunities due to slow analysis.', 'AI that scans MLS listings in real-time, scores properties by investment potential, calculates ROI projections, and alerts investors to off-market deals before competitors.', 'Real estate investors doing 2-20 deals per year and real estate agents wanting data edge', 'Monthly subscription $99-499 based on markets covered. Lead referral fees. Institutional licensing.', 'Hard', 85, 'Scrape Zillow/Redfin APIs. Build scoring model with ML. SMS/email alerts system. Create dashboard with charts.', 'PropTech', '{"Real Estate","Investment","Analytics","Automation"}', false),
('AI Customer Support Replacement', 'SaaS companies spend $50K-500K per year on customer support. Response times are slow, quality is inconsistent, and support agents burn out.', 'Drop-in AI support agent that integrates with any product via JavaScript snippet. Learns your entire docs, past tickets, and product. Handles 95% of queries automatically.', 'SaaS startups with 100-10,000 customers needing to scale support without headcount', 'Per resolution pricing: $0.50-2.00 per ticket. Monthly subscription $299-2999. Enterprise custom.', 'Medium', 90, 'Build RAG pipeline with your docs. Create ticket ingestion system. Build embeddable chat widget. White-label dashboard for customers.', 'SaaS', '{"Customer Support","SaaS","Automation","Chatbot"}', false),
('AI Recruitment Platform', 'Hiring managers spend 30+ hours screening resumes per role. 75% of applications are unqualified. Best candidates are lost to slow processes.', 'AI that screens all applicants in real-time, scores cultural fit and skills alignment, conducts async video interviews, and presents ranked shortlists with explanations.', 'HR teams at companies hiring 10-500 people per year. RPO agencies. In-house recruiters.', 'Per-hire: $200-500. Monthly platform fee: $499-2999. ATS integrations add-on.', 'Hard', 83, 'Build resume parser. Create video interview system. Score candidates with GPT-4. Integrate with LinkedIn/Indeed. Build HR dashboard.', 'HRTech', '{"Recruitment","HR","Automation","Screening"}', false),
('AI Menu & Recipe Optimizer', 'Restaurants waste 4-10% of revenue on food waste. Menus aren''t optimized for profitability. Chefs struggle to create new dishes that sell.', 'AI that analyzes sales data, suggests menu optimizations for max profit, generates new recipe ideas based on seasonal ingredients, and predicts daily demand to reduce waste.', 'Restaurant owners with 1-50 locations. Food service operators. Catering companies.', 'Monthly SaaS: $99-399. Integration with major POS systems. Inventory management add-on.', 'Medium', 78, 'Integrate with Square/Toast POS. Build demand forecasting model. Create recipe suggestion engine. Mobile-first dashboard.', 'FoodTech', '{"Restaurant","Food","Optimization","Waste"}', false)
INSERT INTO ai_prompts (title, prompt_text, platform, category, use_case, tags, is_daily) VALUES
('The Ultimate Business Plan Generator', 'You are a world-class startup advisor with 20 years of experience building and investing in tech companies. I want to start a business in [NICHE]. Please create a comprehensive business plan including: 1) Executive Summary 2) Market Analysis with TAM/SAM/SOM 3) Competitive Analysis 4) Revenue Model with pricing tiers 5) Go-to-Market Strategy 6) 90-day action plan 7) Key metrics to track 8) Potential risks and mitigation. Be specific, data-driven, and actionable. Format as a professional document.', 'ChatGPT', 'Business', 'Business Planning', '{"Business","Startup","Planning","Strategy"}', true),
('Viral Twitter/X Thread Creator', 'You are a viral content strategist who has written threads with 1M+ impressions. Create a viral Twitter/X thread about [TOPIC] that: - Opens with a shocking hook or counterintuitive statement - Contains 8-12 tweets - Each tweet ends with curiosity gap or cliffhanger - Uses short punchy sentences (max 15 words each) - Includes 2-3 data points or statistics - Ends with a clear CTA - Uses power words that trigger engagement. Format: Tweet 1/8, Tweet 2/8, etc. Topic:', 'ChatGPT', 'Content', 'Social Media', '{"Twitter","Viral","Content","Social"}', true),
('10x Your Code Review Speed', 'You are a senior software engineer at Google with expertise in code quality, security, and performance. Review this code and provide: 1) Security vulnerabilities (OWASP Top 10) 2) Performance bottlenecks with specific fixes 3) Code smell and anti-patterns 4) Missing error handling 5) Test coverage gaps 6) Specific refactoring suggestions with code examples. Be brutal and specific. Here''s the code: [PASTE CODE]', 'Claude', 'Coding', 'Code Review', '{"Coding","Review","Security","Performance"}', true),
('Perfect Landing Page Copy', 'You are a CRO specialist and copywriter who has optimized landing pages with 40%+ conversion rates. Write high-converting landing page copy for [PRODUCT/SERVICE] including: 1) Power headline (under 10 words) + subheadline 2) Above-fold hero section 3) 3 core value propositions with proof points 4) Social proof section (testimonial templates) 5) Feature-benefit section (5 features) 6) FAQ section (5 questions) 7) Strong CTA. Target audience: [DESCRIBE AUDIENCE]. Main benefit: [KEY BENEFIT].', 'ChatGPT', 'Marketing', 'Copywriting', '{"Landing Page","Copy","Marketing","CRO"}', false),
('Dream Job Cold Email', 'Act as an elite executive recruiter who places C-suite executives at Fortune 500 companies. Write a cold outreach email for [YOUR NAME] applying to [JOB TITLE] at [COMPANY]. The email should: - Subject line that gets 80%+ open rate - Reference specific company achievement/challenge - Connect candidate''s exact experience to company need - Include one compelling metric or achievement - Social proof (past company or result) - Clear single CTA - Under 150 words total. My background: [PASTE YOUR EXPERIENCE].', 'Claude', 'Career', 'Job Search', '{"Email","Career","Job","Outreach"}', false),
('Create a Stunning Image: Product Photo', 'Professional product photography, [PRODUCT], studio lighting setup, clean white/gradient background, 8K resolution, shallow depth of field, lens flare, photorealistic, commercial advertising style, shot with Canon EOS R5, 100mm macro lens, perfect exposure, color graded --ar 4:5 --v 6 --style raw --q 2', 'Midjourney', 'Design', 'Product Photography', '{"Midjourney","Image","Product","Photography"}', false),
('n8n AI Email Automation Workflow', 'Create an n8n workflow that: 1) Triggers every morning at 8AM 2) Fetches my Gmail inbox from last 24 hours 3) Categorizes each email (urgent/normal/newsletter/spam) using OpenAI 4) Drafts responses for urgent emails using my writing style 5) Summarizes all emails into a daily digest 6) Sends digest to my Telegram. Provide the exact n8n JSON workflow configuration I can import directly.', 'n8n', 'Automation', 'Email Automation', '{"n8n","Automation","Email","Workflow"}', true),
('Gemini: Deep Market Research Report', 'Using your knowledge and web search capabilities, create a comprehensive market research report for the [INDUSTRY] industry in 2024-2025. Include: 1) Market size and CAGR with sources 2) Top 10 players with market share 3) Key trends disrupting the market 4) Consumer behavior shifts 5) Technology adoption curve 6) Investment activity and M&A 7) White space opportunities 8) 3-year forecast. Cite all data sources. Format as an executive briefing.', 'Gemini', 'Research', 'Market Research', '{"Gemini","Research","Market","Analysis"}', false),
('Bolt: Build a Full SaaS App', 'Build a complete SaaS application for [IDEA]. Requirements: - Landing page with pricing tiers - User authentication (email + Google) - Dashboard with key metrics - Core feature: [MAIN FEATURE] - Stripe payment integration - Email notifications - Mobile responsive - Dark mode. Use Next.js 14, Supabase, Tailwind CSS, shadcn/ui. Make it look like a $99/month professional product. Include all pages and components.', 'Bolt', 'Coding', 'App Development', '{"Bolt","SaaS","Development","Full-stack"}', false)
